// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

typedef long long ll;

typedef struct Line {
    ll m; // slope
    ll b; // intercept
} Line;

static inline ll eval(Line *ln, ll x) { return ln->m * x + ln->b; }

typedef struct Node {
    Line line;
    struct Node *left, *right;
} Node;

#define X_MIN 0LL
#define X_MAX 1000000000LL

Node* newNode() {
    Node* nd = (Node*)malloc(sizeof(Node));
    nd->line.m = 0; nd->line.b = LLONG_MIN; // represents -infinity
    nd->left = nd->right = NULL;
    return nd;
}

void addLine(Node **root, Line newLine, ll l, ll r) {
    if (*root == NULL) { *root = newNode(); (*root)->line = newLine; return; }
    Node *node = *root;
    ll mid = (l + r) >> 1;
    int leftBetter = eval(&newLine, l) > eval(&node->line, l);
    int midBetter  = eval(&newLine, mid) > eval(&node->line, mid);
    if (midBetter) {
        Line tmp = node->line; node->line = newLine; newLine = tmp;
    }
    if (r - l == 0) return;
    if (leftBetter != midBetter) {
        addLine(&node->left, newLine, l, mid);
    } else {
        addLine(&node->right, newLine, mid+1, r);
    }
}

void addSegment(Node **root, Line newLine, ll segL, ll segR, ll l, ll r) {
    if (segR < l || r < segL) return;
    if (segL <= l && r <= segR) { addLine(root, newLine, l, r); return; }
    ll mid = (l + r) >> 1;
    addSegment(root, newLine, segL, segR, l, mid);
    addSegment(root, newLine, segL, segR, mid+1, r);
}

ll query(Node *root, ll x, ll l, ll r) {
    if (!root) return LLONG_MIN;
    ll cur = eval(&root->line, x);
    if (l == r) return cur;
    ll mid = (l + r) >> 1;
    if (x <= mid) return cur > query(root->left, x, l, mid) ? cur : query(root->left, x, l, mid);
    else return cur > query(root->right, x, mid+1, r) ? cur : query(root->right, x, mid+1, r);
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, Q; scanf("%d %d", &N, &Q);
        ll *lastTime = (ll*)calloc(N, sizeof(ll));
        ll *lastSpeed = (ll*)calloc(N, sizeof(ll));
        ll *dist = (ll*)calloc(N, sizeof(ll));
        Node *root = NULL;
        // initially each cyclist has line y = 0 (slope 0, intercept 0) valid from 0 to INF
        Line init = {0, 0};
        for(int i=0;i<N;i++) addSegment(&root, init, 0, X_MAX, X_MIN, X_MAX);
        for(int i=0;i<Q;i++){
            int type; scanf("%d", &type);
            if(type==1){
                ll time; int cyclist; ll newSpeed; scanf("%lld %d %lld", &time, &cyclist, &newSpeed);
                cyclist--;
                // close previous segment
                ll oldSpeed = lastSpeed[cyclist];
                ll lt = lastTime[cyclist];
                ll a = dist[cyclist] - oldSpeed * lt; // intercept
                Line seg = {oldSpeed, a};
                addSegment(&root, seg, lt, time-1, X_MIN, X_MAX);
                // update distance up to 'time'
                dist[cyclist] += oldSpeed * (time - lt);
                lastSpeed[cyclist] = newSpeed;
                lastTime[cyclist] = time;
                // add new line for future (from time onward)
                ll a2 = dist[cyclist] - newSpeed * time;
                Line newLine = {newSpeed, a2};
                addSegment(&root, newLine, time, X_MAX, X_MIN, X_MAX);
            } else {
                ll time; scanf("%lld", &time);
                ll ans = query(root, time, X_MIN, X_MAX);
                if(ans==LLONG_MIN) ans = 0; // safety
                printf("%lld\n", ans);
            }
        }
        free(lastTime); free(lastSpeed); free(dist);
        // Note: memory of the Li Chao tree is not freed for brevity (acceptable in contest limits).
    }
    return 0;
}

